INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (17, '31', 'Dış görünüşüne, saçına, sakalına, kişisel hijyenine dikkat eder. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (17, '32', 'Şirketin eğitimlerine aktif olarak katılır, atanmış eğitimlerini tamamlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (17, '33', 'Restoran hedeflerinden haberdardır, hedef için elinden gelen gayreti gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (17, '34', 'İnsan Kaynakları tarafından yayınlanan Şirket Davranış Talimatına uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (17, '35', 'Mazeret bildirmeden işe gelmemezlik yapmaz. Vardiya ve mola düzenine uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (18, 4, 'Kasa');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '36', 'Müşterilere karşı güleryüzlü ve naziktir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '37', 'Güleryüzlü bir şekilde karşılama  yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '38', 'Müşteri siparişlerini standartlara uygun ve doğru bir şekilde alır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '39', 'Kasa programına hakimdir. İşlemleri doğru ve hızlı bir şekilde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '40', 'Ürünlerle ve içerikleri ile ilgili bilgilidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '41', 'Operasyonel prosedür ve talimatları bilir, bunlara uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '42', 'Menü fiyatları ve pormosyonlarla ilgili bilgilidir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '43', 'Paket serviste doğru paketleme ve doğru ürün teslimi yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '44', 'Çalışma süresince Gıda Güvenliği ve İSG kurallarına uygun hareket eder.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '45', 'Çalıştığı ekipmanları özenli ve titiz kullanır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '46', 'Kasa düzenini sağlar, dağınık bir görüntü verilmesine izin vermez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '47', 'Zor müşteriler ile iletişim kurabilir, gerekli yönlendirmeleri yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '48', 'Kasa açığı verilmemesi için gerekli özen ve dikkati gösterir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '49', 'İşine ve markaya aidiyet duyar, işini severek yapar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (18, '50', 'Yöneticisinin verdiği talimatlara uyar.');
INSERT INTO position_categories (id, positionId, name) VALUES (19, 5, 'Görev Bilinci');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (19, '1', 'Yaptığı işi en iyi şekilde yapar. İş disiplini ve görev bilinci yüksektir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (19, '2', 'Sorumluluğundaki işleri, şirket kural ve prosedürlerine uygun bir biçimde gerçekleştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (19, '3', 'İşine, kuruma ve kendisine sunulan kaynaklara zarar verecek hiçbir davranış sergilemez.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (19, '4', 'Ahlaki ve etik değerlere uygun davranır. Davranışlarının sorumluluğunu üstlenir.');
INSERT INTO position_categories (id, positionId, name) VALUES (20, 5, 'İletişim Becerisi');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (20, '5', 'Karşındakini dinler ve verilmek istenen mesajı doğru bir şekilde anlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (20, '6', 'Söylemek istediklerini, açık, kısa ve net bir biçimde karşı tarafa aktarır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (20, '7', 'İşle ilgili konularla ilgili bilgiyi zamanında aktarır ve paylaşır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (20, '8', 'Her türlü iletişimde empati kurmaya özen gösterir. Gerektiğinde iletişim tarzını değiştirebilir.');
INSERT INTO position_categories (id, positionId, name) VALUES (21, 5, 'Analitik Düşünme ve Problem Çözme');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (21, '9', 'Gelişmekte olan problemleri görür, önleyici davranış geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (21, '10', 'Durum ve problem karşısında alacağı hareketin sonucunu bilir. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (21, '11', 'Mevcut sorunu gidermek için alternatif çözüm yolları geliştirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (21, '12', 'Benzer sorunlar arasında ilişki kurar; geçmişteki deneyimlerden faydalanır.');
INSERT INTO position_categories (id, positionId, name) VALUES (22, 5, 'Kalite Odaklılık');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (22, '13', 'Mevcut düzen ve iş yapma yöntemine uygun çalışır. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (22, '14', 'Kaliteyi belirlenen standartlara göre uyarlar.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (22, '15', 'İş yapma yöntemini sürekli geliştirmeye, verimlilik ve etkililiği artırmaya odaklı çalışır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (22, '16', 'İş yapma yöntemine ilişkin akış ve prosedürlerdeki yeniliklere adapte olur.');
INSERT INTO position_categories (id, positionId, name) VALUES (23, 5, 'Takım Çalışması ve İşbirliği');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (23, '17', 'Çalışma ortamında iyi ilişkiler kurar ve korur. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (23, '18', 'Takım arkadaşlarının yardıma ihtiyacı olduğunda gerekli destekte bulunur.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (23, '19', 'Takım arkadaşlarını, ortak başarı için heveslendirir, onları motive eder. "Biz" olgusunu yaygınlaştır.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (23, '20', 'Takımdaki farklı görüşlere karşı toleranslıdır ve destekleyicidir.');
INSERT INTO position_categories (id, positionId, name) VALUES (24, 5, 'Yönetim Becerileri ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '21', 'Doğru insanları belirleyerek ihtiyaçlar doğrultusunda görev dağılımını net bir şekilde yapar. ');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '22', 'Ekibine mentorluk yapar, yapıcı geri bildirimlerde bulunur ve yönlendirir.');
INSERT INTO position_questions (categoryId, questionNumber, questionText) VALUES (24, '23', 'Ekibini motive eder, olumsuzluk yaratacak durumların önüne geçmek için çaba sarf eder.');

